const KEY='restart-v6-data';
const DEFAULT_CATEGORIES={expense:['飲食','飲料','香菸','交通','娛樂','生活用品','寵物','保險','信用卡','貸款','醫療','居住','其他'],income:['薪資','獎金','兼職','退款','賣東西','投資收入','其他'],saving:['存款']};
const DEFAULT_DEBT_TYPES=['信貸','房貸','車貸','學貸','信用卡','信用卡分期','民間借款','親友借款','融資','稅款','保費分期','其他'];
const DEFAULT_ASSET_TYPES=['現金','銀行帳戶','數位帳戶','外幣帳戶','電子錢包','儲值卡','投資帳戶','緊急預備金','其他'];
const D={startDate:new Date().toISOString().slice(0,10),reason:'',heroPhoto:'',heroTitle:'重新開始',heroText:'今天不賭，因為我值得更好的生活。',bgColor:'#f7f6f3',checkins:[],best:0,relapses:[],debts:[],assets:[],goals:[],transactions:[],journals:[],photos:[],sosSuccess:[],categories:structuredClone(DEFAULT_CATEGORIES),debtTypes:[...DEFAULT_DEBT_TYPES],assetTypes:[...DEFAULT_ASSET_TYPES],snapshots:[],forecasts:{current:{},next:{}}};
const $=id=>document.getElementById(id),fmt=n=>'NT$'+Math.round(Number(n||0)).toLocaleString(),today=()=>new Date().toISOString().slice(0,10),uid=()=>Date.now()+Math.floor(Math.random()*10000),esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
function load(){let x={};try{x=JSON.parse(localStorage.getItem(KEY)||'{}')||{}}catch{};const d={...structuredClone(D),...x};d.debts=Array.isArray(d.debts)?d.debts:[];d.assets=Array.isArray(d.assets)?d.assets:[];d.goals=Array.isArray(d.goals)?d.goals:[];d.transactions=Array.isArray(d.transactions)?d.transactions:[];d.journals=Array.isArray(d.journals)?d.journals:[];d.photos=Array.isArray(d.photos)?d.photos:[];d.checkins=Array.isArray(d.checkins)?d.checkins:[];d.relapses=Array.isArray(d.relapses)?d.relapses:[];d.sosSuccess=Array.isArray(d.sosSuccess)?d.sosSuccess:[];d.categories={expense:[...new Set([...(d.categories?.expense||[]),...DEFAULT_CATEGORIES.expense])],income:[...new Set([...(d.categories?.income||[]),...DEFAULT_CATEGORIES.income])],saving:[...new Set([...(d.categories?.saving||[]),...DEFAULT_CATEGORIES.saving])]};d.debtTypes=[...new Set([...(d.debtTypes||[]),...d.debts.map(x=>x.type).filter(Boolean),...DEFAULT_DEBT_TYPES])];d.assetTypes=[...new Set([...(d.assetTypes||[]),...d.assets.map(x=>x.type).filter(Boolean),...DEFAULT_ASSET_TYPES])];d.assets.forEach(a=>{if(a.available===undefined)a.available=true});d.forecasts=d.forecasts&&typeof d.forecasts==='object'?d.forecasts:{current:{},next:{}};d.forecasts.current=d.forecasts.current||{};d.forecasts.next=d.forecasts.next||{};d.debts.forEach(x=>{x.amount=Number(x.amount||0);x.rate=Number(x.rate||0);x.terms=Number(x.terms||0);x.payment=Number(x.payment||0);const est=Number(x.currentDue||0)>0?Number(x.currentDue):debtPayment(x);x.currentDue=Math.max(0,est);x.currentPaid=Math.max(0,Math.min(Number(x.currentPaid||0),x.currentDue));});return d}
let state=load(),ledgerFilter='all',sosIndex=0,timerHandle=null,excelPreviewData=null;
function save(){localStorage.setItem(KEY,JSON.stringify(state));renderAll();return true}
function notify(msg){const n=$('notice');n.textContent=msg;n.classList.add('show');setTimeout(()=>n.classList.remove('show'),1500)}
function showPage(id,btn){document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));$(id).classList.add('active');document.querySelectorAll('.nav button').forEach(x=>x.classList.remove('active'));if(btn)btn.classList.add('active');else [...document.querySelectorAll('.nav button')].find(x=>x.getAttribute('onclick')?.includes(`'${id}'`))?.classList.add('active');$('fab').style.display=id==='ledger'?'block':'none';window.scrollTo({top:0,behavior:'smooth'});if(id==='ledger')renderLedger();if(id==='finance')renderFinance()}
function openModal(id){$(id).classList.add('open')}function closeModal(id){$(id).classList.remove('open')}
function currentStreak(){if(!state.checkins.length)return 0;const set=new Set(state.checkins),d=new Date();let count=0;for(;;){const k=d.toISOString().slice(0,10);if(set.has(k)){count++;d.setDate(d.getDate()-1)}else break}return count}
function isCreditCardDebtType(type){return ['信用卡','信用卡卡費'].includes(String(type||'').trim())}
function fillTypeSelect(id,items,value){const el=$(id);const list=[...new Set([...(items||[]),value].filter(Boolean))];el.innerHTML=list.map(x=>`<option value="${esc(x)}">${esc(x)}</option>`).join('');if(value)el.value=value}
function totals(){const assets=state.assets.filter(x=>x.available!==false).reduce((s,x)=>s+Number(x.amount||0),0),debt=state.debts.reduce((s,x)=>s+Number(x.amount||0),0),cards=state.debts.filter(x=>isCreditCardDebtType(x.type)).reduce((s,x)=>s+Number(x.amount||0),0),monthly=state.debts.reduce((s,x)=>s+debtCurrentRemaining(x),0);return{assets,debt,cards,monthly}}
function debtPayment(x){if(Number(x.payment)>0)return Number(x.payment);const p=Number(x.amount||0),n=Math.max(1,Number(x.terms||1)),r=Number(x.rate||0)/1200;if(!r)return p/n;return p*r*Math.pow(1+r,n)/(Math.pow(1+r,n)-1)}
function debtCurrentDue(x){const v=Number(x.currentDue||0);return v>0?v:Math.min(Number(x.amount||0),debtPayment(x))}
function debtCurrentRemaining(x){return Math.max(0,debtCurrentDue(x)-Number(x.currentPaid||0))}
function debtIsOverdue(x){return !!(x.due&&dateDiff(x.due)<0&&debtCurrentRemaining(x)>0&&Number(x.amount||0)>0)}
function dateDiff(date){if(!date)return 9999;const a=new Date(today()+'T00:00:00'),b=new Date(date+'T00:00:00');return Math.round((b-a)/86400000)}
function calcHealth(){const t=totals(),month=today().slice(0,7),inc=state.transactions.filter(x=>x.type==='income'&&x.date?.startsWith(month)).reduce((s,x)=>s+Number(x.amount||0),0),exp=state.transactions.filter(x=>x.type==='expense'&&x.date?.startsWith(month)).reduce((s,x)=>s+Number(x.amount||0),0),sav=state.transactions.filter(x=>x.type==='saving'&&x.date?.startsWith(month)).reduce((s,x)=>s+Number(x.amount||0),0);let score=50,reasons=[];if(t.debt===0){score+=25;reasons.push('目前沒有負債')}else{const ratio=t.assets/Math.max(1,t.debt);score+=Math.min(20,ratio*25);if(ratio<.1)reasons.push('可用資產相對負債偏低')}if(t.monthly>0){const cover=t.assets/t.monthly;if(cover>=3)score+=15;else if(cover>=1)score+=5;else{score-=15;reasons.push('可用資產不足一個月固定還款')}}if(inc>0){const remain=inc-exp-sav;if(remain>=0)score+=10;else{score-=12;reasons.push('本月支出與存款高於收入')}}if(t.cards>t.assets&&t.cards>0){score-=12;reasons.push('信用卡卡費高於可用資產')}const overdue=state.debts.filter(x=>debtIsOverdue(x)).length;if(overdue){score-=20;reasons.push(`有 ${overdue} 筆款項已逾期`)}const high=state.debts.filter(x=>Number(x.rate)>=10&&x.amount>0).length;if(high){score-=8;reasons.push('存在高利率負債，建議優先處理')}const goal=state.goals[0];if(goal&&Number(goal.current)>0)score+=Math.min(10,Number(goal.current)/Math.max(1,Number(goal.target))*10);score=Math.max(0,Math.min(100,Math.round(score)));return{score,reasons,inc,exp,sav}}
function renderHome(){const st=currentStreak(),best=Math.max(Number(state.best||0),st);state.best=best;$('homeStreak').textContent=st+' 天';$('homeBest').textContent=best+' 天';$('homeRelapse').textContent=state.relapses.length+' 次';const t=totals();$('snapDebt').innerHTML=moneyHtml(t.debt);$('snapAsset').innerHTML=moneyHtml(t.assets);const g=state.goals[0];$('snapGoal').textContent=g?Math.min(100,Math.round(Number(g.current||0)/Math.max(1,Number(g.target||1))*100))+'%':'0%';$('heroTitleView').textContent=state.heroTitle||'重新開始';$('heroTextView').textContent=state.heroText||'今天不賭，因為我值得更好的生活。';$('hero').classList.toggle('has-photo',!!state.heroPhoto);if(state.heroPhoto)$('heroImg').src=state.heroPhoto;const stages=st>=365?['🌳','你已經長成一棵大樹']:st>=200?['🌲','你正在長成大樹']:st>=100?['🌳','你的根越來越穩']:st>=30?['🌿','你已經是一棵小樹']:st>=7?['🌱','小苗正在成長']:st>=1?['🌱','種子已經發芽']:['🌰','種子正在等待發芽'];$('treeEmoji').textContent=stages[0];$('treeText').textContent=stages[1];const ms=[1,7,30,100,200,365];$('milestones').innerHTML=ms.map(x=>`<div class="mile ${best>=x?'done':''}"><i></i>${x}天</div>`).join('');const next=ms.find(x=>x>st);$('nextMilestone').textContent=next?`${st}/${next} 天`:'365 天完成';$('checkBtn').textContent=state.checkins.includes(today())?'✅ 今天已簽到':'✅ 今天不賭'}
function checkIn(){if(!state.checkins.includes(today())){state.checkins.push(today());state.best=Math.max(state.best||0,currentStreak());save();notify('今天也成功了')}else notify('今天已經簽到')}
function recordRelapse(){if(!confirm('你願意誠實記錄，已經是在重新開始。\n\n確認今天發生復賭？'))return;const reason=prompt('復賭原因（例如：想翻本、壓力、無聊）','想翻本')||'未填寫';const loss=Number(prompt('本次損失金額（可填 0）','0')||0);state.relapses.push({id:uid(),date:today(),reason,loss,streak:currentStreak()});state.best=Math.max(state.best||0,currentStreak());state.checkins=[];save();notify('滑倒了沒關係，明天重新開始')}
function moneyHtml(n){const v=Math.round(Number(n||0)).toLocaleString('zh-TW');return `<span class="money-prefix">NT$</span><span class="money-value">${v}</span>`}
function renderFinance(){const t=totals(),h=calcHealth();$('finDebt').innerHTML=moneyHtml(t.debt);$('finAsset').innerHTML=moneyHtml(t.assets);$('finDue').innerHTML=moneyHtml(t.monthly);$('healthScore').textContent=h.score;$('healthRing').style.setProperty('--score',h.score);const label=h.score>=80?'穩定':h.score>=60?'注意':h.score>=40?'偏高風險':'高風險';$('healthLabel').textContent='目前健康度：'+h.score+' 分｜'+label;$('healthText').textContent=h.reasons[0]||'目前方向穩定，請持續保留還款緩衝與存款。';renderForecasts();renderAlerts(h,t);renderUpcoming();renderDebts();renderAssets();renderGoals()}
function renderAlerts(h,t){const arr=[];state.debts.filter(x=>x.amount>0&&x.due&&debtCurrentRemaining(x)>0).sort((a,b)=>a.due.localeCompare(b.due)).slice(0,5).forEach(x=>{const days=dateDiff(x.due),txt=days<0?`已逾期 ${Math.abs(days)} 天`:days===0?'今天到期':`還有 ${days} 天到期`;if(days<=7)arr.push({type:days<=3?'bad':'warn',text:`${x.name||x.type} ${txt}，本期尚欠 ${fmt(debtCurrentRemaining(x))}`})});h.reasons.forEach(r=>arr.push({type:h.score<50?'bad':'warn',text:r}));if(!arr.length)arr.push({type:'',text:'目前沒有急迫風險，請持續按計畫還款與存款。'});$('financeAlerts').innerHTML=arr.map(x=>`<div class="alert ${x.type}">${esc(x.text)}</div>`).join('')}
function renderUpcoming(){const xs=state.debts.filter(x=>x.amount>0&&x.due&&debtCurrentRemaining(x)>0).map(x=>({...x,days:dateDiff(x.due)})).filter(x=>x.days<=30).sort((a,b)=>a.days-b.days);$('upcomingList').innerHTML=xs.length?xs.map(x=>`<div class="upcoming-item ${x.days<=3?'urgent':x.days<=7?'soon':''}"><div><strong>${esc(x.name||x.type)}</strong><div class="sub">${esc(x.due)}</div></div><div class="right"><strong>${fmt(debtCurrentRemaining(x))}</strong><div class="sub">${x.days<0?'已逾期 '+Math.abs(x.days)+' 天':x.days===0?'今天到期':'還有 '+x.days+' 天'}</div></div></div>`).join(''):'<div class="empty">未來 30 天沒有需繳款項</div>'}
function renderDebts(){$('debtList').innerHTML=state.debts.length?state.debts.map(x=>{const rem=debtCurrentRemaining(x),over=debtIsOverdue(x),days=x.due?dateDiff(x.due):9999;return `<div class="item"><div class="item-head"><div><div class="item-title">${esc(x.name||x.type)}</div><div class="muted small">${esc(x.type)}</div></div><div class="item-amount">${fmt(x.amount)}</div></div>${over?`<div class="debt-overdue">已逾期 ${Math.abs(days)} 天，尚欠 ${fmt(rem)}</div>`:''}<div class="detail-list"><div class="detail-row"><span class="label">利率</span><span class="value">${Number(x.rate||0)}%</span></div><div class="detail-row"><span class="label">每期約</span><span class="value">${fmt(debtPayment(x))}</span></div><div class="detail-row"><span class="label">本期應繳</span><span class="value">${fmt(debtCurrentDue(x))}</span></div><div class="detail-row"><span class="label">本期已繳</span><span class="value">${fmt(x.currentPaid||0)}</span></div><div class="detail-row ${rem>0&&days<0?'bad':rem>0&&days<=7?'warn':''}"><span class="label">剩餘繳費</span><span class="value">${fmt(rem)}</span></div><div class="detail-row"><span class="label">剩餘期數</span><span class="value">${Number(x.terms||0)} 期</span></div><div class="detail-row"><span class="label">下期繳費</span><span class="value">${esc(x.due||'未設定')}</span></div></div><div class="actions"><button class="tiny edit" onclick="openDebt('${x.id}')">編輯</button><button class="tiny pay" onclick="openPay('${x.id}')">繳費</button><button class="tiny delete" onclick="deleteDebt('${x.id}')">刪除</button></div></div>`}).join(''):'<div class="empty">尚未新增負債</div>'}
function renderAssets(){$('assetList').innerHTML=state.assets.length?state.assets.map(x=>`<div class="item"><div class="item-head"><div><div class="item-title">${esc(x.name||x.type)}</div></div><div class="item-amount">${fmt(x.amount)}</div></div><div class="detail-list"><div class="detail-row"><span class="label">類型</span><span class="value">${esc(x.type)}</span></div><div class="detail-row"><span class="label">可用資產</span><span class="value">${x.available===false?'不計入':'計入'}</span></div></div><div class="actions"><button class="tiny edit" onclick="openAsset('${x.id}')">編輯</button><button class="tiny delete" onclick="deleteAsset('${x.id}')">刪除</button></div></div>`).join(''):'<div class="empty">尚未新增資產</div>'}
function renderGoals(){$('goalList').innerHTML=state.goals.length?state.goals.map(x=>{const p=Math.min(100,Math.round(Number(x.current||0)/Math.max(1,Number(x.target||1))*100)),txs=state.transactions.filter(t=>t.type==='saving'&&String(t.goalId)===String(x.id)).sort((a,b)=>(b.date||'').localeCompare(a.date||'')),last=txs[0]?.date||'尚無存款紀錄';return `<div class="item"><div class="item-head"><div><div class="item-title">${esc(x.name)}</div></div><div class="item-amount">${p}%</div></div><div class="detail-list"><div class="detail-row"><span class="label">目前已存</span><span class="value">${fmt(x.current)}</span></div><div class="detail-row"><span class="label">目標金額</span><span class="value">${fmt(x.target)}</span></div><div class="detail-row"><span class="label">還差</span><span class="value">${fmt(Math.max(0,x.target-x.current))}</span></div><div class="detail-row"><span class="label">目標日期</span><span class="value">${esc(x.date||'未設定')}</span></div><div class="detail-row"><span class="label">累積存款筆數</span><span class="value">${txs.length} 筆</span></div><div class="detail-row"><span class="label">最近一次存款</span><span class="value">${esc(last)}</span></div></div><div class="actions"><button class="tiny edit" onclick="openGoal('${x.id}')">編輯</button><button class="tiny delete" onclick="deleteGoal('${x.id}')">刪除</button></div></div>`}).join(''):'<div class="empty">尚未新增存錢目標</div>'}
function openDebt(id=''){const x=state.debts.find(y=>String(y.id)===String(id));$('debtId').value=x?.id||'';fillTypeSelect('debtType',state.debtTypes,x?.type||'信貸');$('debtName').value=x?.name||'';$('debtAmount').value=x?.amount||'';$('debtRate').value=x?.rate||'';$('debtTerms').value=x?.terms||'';$('debtPayment').value=x?.payment||'';$('debtCurrentDue').value=x?debtCurrentDue(x):'';$('debtCurrentPaid').value=x?.currentPaid||0;$('debtDue').value=x?.due||'';$('debtNote').value=x?.note||'';openModal('debtModal')}
function saveDebt(){const id=$('debtId').value,old=state.debts.find(y=>String(y.id)===String(id)),x={id:id||uid(),type:$('debtType').value,name:$('debtName').value.trim()||$('debtType').value,amount:Number($('debtAmount').value||0),rate:Number($('debtRate').value||0),terms:Number($('debtTerms').value||0),payment:Number($('debtPayment').value||0),currentDue:Number($('debtCurrentDue').value||0),currentPaid:Number($('debtCurrentPaid').value||0),due:$('debtDue').value,note:$('debtNote').value};if(x.currentDue<=0)x.currentDue=Math.min(x.amount,debtPayment(x));x.currentPaid=Math.max(0,Math.min(x.currentPaid,x.currentDue));if(id){const i=state.debts.findIndex(y=>String(y.id)===String(id));state.debts[i]={...old,...x}}else state.debts.push(x);save();closeModal('debtModal')}
function deleteDebt(id){if(confirm('刪除這筆負債？')){state.debts=state.debts.filter(x=>String(x.id)!==String(id));save()}}
function openAsset(id=''){const x=state.assets.find(y=>String(y.id)===String(id));$('assetId').value=x?.id||'';fillTypeSelect('assetType',state.assetTypes,x?.type||'銀行帳戶');$('assetName').value=x?.name||'';$('assetAmount').value=x?.amount||'';$('assetAvailable').checked=x?.available!==false;openModal('assetModal')}
function saveAsset(){const id=$('assetId').value,x={id:id||uid(),type:$('assetType').value,name:$('assetName').value.trim()||$('assetType').value,amount:Number($('assetAmount').value||0),available:$('assetAvailable').checked};if(id){const i=state.assets.findIndex(y=>String(y.id)===String(id));state.assets[i]=x}else state.assets.push(x);save();closeModal('assetModal');notify('已儲存')}
function deleteAsset(id){if(confirm('刪除這筆資產？')){state.assets=state.assets.filter(x=>String(x.id)!==String(id));save()}}
function openGoal(id=''){const x=state.goals.find(y=>String(y.id)===String(id));$('goalId').value=x?.id||'';$('goalName').value=x?.name||'';$('goalTarget').value=x?.target||'';$('goalCurrent').value=x?.current||'';$('goalDate').value=x?.date||'';openModal('goalModal')}
function saveGoal(){const id=$('goalId').value,x={id:id||uid(),name:$('goalName').value.trim()||'存錢目標',target:Number($('goalTarget').value||0),current:Number($('goalCurrent').value||0),date:$('goalDate').value};if(id){const i=state.goals.findIndex(y=>String(y.id)===String(id));state.goals[i]=x}else state.goals.push(x);save();closeModal('goalModal');notify('已儲存')}
function deleteGoal(id){if(confirm('刪除這個目標？')){state.goals=state.goals.filter(x=>String(x.id)!==String(id));save()}}
function openPay(id){const d=state.debts.find(x=>String(x.id)===String(id));if(!d)return;$('payDebtId').value=id;$('payMode').value='full';$('payAmount').value=Math.min(Number(d.amount||0),debtCurrentRemaining(d)).toFixed(0);$('payAccount').innerHTML=state.assets.map(a=>`<option value="${a.id}">${esc(a.name||a.type)}｜${fmt(a.amount)}</option>`).join('');togglePayMode();openModal('payModal')}
function togglePayMode(){const d=state.debts.find(x=>String(x.id)===String($('payDebtId').value));if(!d)return;if($('payMode').value==='clear')$('payAmount').value=Math.round(Number(d.amount||0));else $('payAmount').value=Math.round(debtCurrentRemaining(d))}
function addMonths(date,n=1){const d=new Date((date||today())+'T00:00:00');d.setMonth(d.getMonth()+n);return d.toISOString().slice(0,10)}
function confirmPayment(){const id=$('payDebtId').value,d=state.debts.find(x=>String(x.id)===String(id)),a=state.assets.find(x=>String(x.id)===String($('payAccount').value));if(!d||!a)return;let amount=Number($('payAmount').value||0),mode=$('payMode').value;if(mode==='clear')amount=Number(d.amount||0);const remBefore=debtCurrentRemaining(d);if(mode!=='clear')amount=Math.min(amount,remBefore);if(amount<=0)return;if(a.amount<amount&&!confirm('帳戶餘額不足，仍要記錄嗎？'))return;a.amount=Number(a.amount||0)-amount;d.amount=Math.max(0,Number(d.amount||0)-amount);let label='部分繳費';if(mode==='clear'){d.currentPaid=0;d.currentDue=0;d.terms=0;d.payment=0;d.due='';label='提前清償'}else{d.currentDue=debtCurrentDue(d);d.currentPaid=Math.min(d.currentDue,Number(d.currentPaid||0)+amount);if(debtCurrentRemaining(d)<=0.009){label='本期繳清';d.terms=Math.max(0,Number(d.terms||0)-1);d.due=d.terms>0?addMonths(d.due||today(),1):'';d.currentPaid=0;d.currentDue=d.terms>0&&d.amount>0?Math.min(d.amount,debtPayment(d)):0}else label='本期部分繳費'}state.transactions.push({id:uid(),type:'expense',date:today(),category:'貸款',amount,accountId:String(a.id),note:`${d.name||d.type} ${label}`,systemGenerated:true,debtId:d.id});save();closeModal('payModal')}
function openTransaction(id=''){const x=state.transactions.find(y=>String(y.id)===String(id));$('txId').value=x?.id||'';$('txType').value=x?.type||'expense';$('txDate').value=x?.date||today();$('txAmount').value=x?.amount||'';$('txImportance').value=String(x?.importance||1);$('txNote').value=x?.note||'';$('receiptPreview').style.display=x?.receipt?'block':'none';if(x?.receipt)$('receiptPreview').src=x.receipt;refreshTxForm();setTimeout(()=>{$('txCategory').value=x?.category||$('txCategory').value;$('txAccount').value=x?.accountId||'';$('txGoal').value=x?.goalId||''},0);openModal('txModal')}
function refreshTxForm(){const type=$('txType').value,cats=state.categories[type]||[];$('txCategory').innerHTML=cats.map(c=>`<option>${esc(c)}</option>`).join('');$('goalField').classList.toggle('hidden',type!=='saving');$('txGoal').innerHTML=state.goals.map(g=>`<option value="${g.id}">${esc(g.name)}</option>`).join('');const opts=[...state.assets.map(a=>`<option value="asset:${a.id}">${esc(a.name||a.type)}｜${fmt(a.amount)}</option>`),...state.debts.filter(d=>isCreditCardDebtType(d.type)).map(d=>`<option value="debt:${d.id}">${esc(d.name||d.type)}｜卡費 ${fmt(d.amount)}</option>`)];$('txAccount').innerHTML='<option value="">不連動帳戶</option>'+opts.join('')}
async function fileToData(file,max=1200,quality=.78){if(!file)return'';return new Promise((resolve,reject)=>{const r=new FileReader();r.onerror=reject;r.onload=()=>{const img=new Image();img.onload=()=>{const s=Math.min(1,max/Math.max(img.width,img.height)),c=document.createElement('canvas');c.width=Math.max(1,Math.round(img.width*s));c.height=Math.max(1,Math.round(img.height*s));c.getContext('2d').drawImage(img,0,0,c.width,c.height);resolve(c.toDataURL('image/jpeg',quality))};img.onerror=reject;img.src=r.result};r.readAsDataURL(file)})}
async function saveTransaction(){const id=$('txId').value,type=$('txType').value,amount=Number($('txAmount').value||0);if(amount<=0)return notify('請輸入金額');const old=state.transactions.find(x=>String(x.id)===String(id));if(old?.systemGenerated)return notify('系統自動記帳請由財務頁管理');if(old)reverseTransaction(old);let receipt=old?.receipt||'';const f=$('txReceipt').files[0];if(f)receipt=await fileToData(f,1000,.72);const tx={id:id||uid(),type,date:$('txDate').value||today(),category:$('txCategory').value,amount,accountId:$('txAccount').value,goalId:type==='saving'?$('txGoal').value:'',importance:Number($('txImportance').value||1),note:$('txNote').value,receipt,systemGenerated:false};applyTransaction(tx);if(id){const i=state.transactions.findIndex(x=>String(x.id)===String(id));state.transactions[i]=tx}else state.transactions.push(tx);save();closeModal('txModal');notify('已儲存')}
function applyTransaction(tx){if(tx.syncApplied===false)return;if(tx.accountId){const [kind,id]=String(tx.accountId).split(':');if(kind==='asset'){const a=state.assets.find(x=>String(x.id)===String(id));if(a)a.amount=Number(a.amount||0)+(tx.type==='income'?tx.amount:-tx.amount)}else if(kind==='debt'&&tx.type==='expense'){const d=state.debts.find(x=>String(x.id)===String(id));if(d)d.amount=Number(d.amount||0)+tx.amount}}if(tx.type==='saving'&&tx.goalId){const g=state.goals.find(x=>String(x.id)===String(tx.goalId));if(g)g.current=Number(g.current||0)+tx.amount}}
function reverseTransaction(tx){if(tx.syncApplied===false)return;if(tx.accountId){const [kind,id]=String(tx.accountId).split(':');if(kind==='asset'){const a=state.assets.find(x=>String(x.id)===String(id));if(a)a.amount=Number(a.amount||0)-(tx.type==='income'?tx.amount:-tx.amount)}else if(kind==='debt'&&tx.type==='expense'){const d=state.debts.find(x=>String(x.id)===String(id));if(d)d.amount=Math.max(0,Number(d.amount||0)-tx.amount)}}if(tx.type==='saving'&&tx.goalId){const g=state.goals.find(x=>String(x.id)===String(tx.goalId));if(g)g.current=Math.max(0,Number(g.current||0)-tx.amount)}}
function deleteTransaction(id){const x=state.transactions.find(y=>String(y.id)===String(id));if(!x)return;if(x.systemGenerated){if(!confirm('這筆由財務繳款自動產生。刪除記帳不會還原負債繳款紀錄，仍要刪除嗎？'))return;state.transactions=state.transactions.filter(y=>String(y.id)!==String(id));save();return}if(confirm('刪除這筆記帳？')){reverseTransaction(x);state.transactions=state.transactions.filter(y=>String(y.id)!==String(id));save()}}
function setLedgerFilter(f,btn){ledgerFilter=f;document.querySelectorAll('.ledger-toolbar .chip').forEach(x=>x.classList.remove('active'));btn.classList.add('active');renderLedger()}
function renderLedger(){const t=today(),m=t.slice(0,7),sum=(type,prefix)=>state.transactions.filter(x=>x.type===type&&x.date?.startsWith(prefix)).reduce((s,x)=>s+Number(x.amount||0),0);$('todayIncome').textContent=fmt(sum('income',t));$('todayExpense').textContent=fmt(sum('expense',t));$('todaySaving').textContent=fmt(sum('saving',t));$('monthIncome').textContent=fmt(sum('income',m));$('monthExpense').textContent=fmt(sum('expense',m));$('monthSaving').textContent=fmt(sum('saving',m));const q=$('txSearch').value.trim().toLowerCase();let xs=[...state.transactions].sort((a,b)=>(b.date||'').localeCompare(a.date||'')||Number(b.id)-Number(a.id));if(ledgerFilter!=='all')xs=xs.filter(x=>x.type===ledgerFilter);if(q)xs=xs.filter(x=>(x.category+' '+x.note+' '+x.amount).toLowerCase().includes(q));$('transactionList').innerHTML=xs.length?xs.map(x=>`<div class="transaction"><div><strong>${esc(x.category)}</strong><div class="muted small">${esc(x.date)}${x.note?'｜'+esc(x.note):''}${x.systemGenerated?'｜由財務繳款自動產生':''}</div></div><div style="text-align:right"><strong class="${x.type}">${x.type==='income'?'+':'-'}${fmt(x.amount)}</strong><div class="actions" style="justify-content:flex-end"><button class="tiny edit" onclick="openTransaction('${x.id}')">編輯</button><button class="tiny delete" onclick="deleteTransaction('${x.id}')">刪除</button></div></div></div>`).join(''):'<div class="empty">尚無記帳資料</div>'}
function openCategoryManager(){renderCategoryManager();openModal('categoryModal')}function renderCategoryManager(){const type=$('catType').value,cats=state.categories[type]||[];$('categoryList').innerHTML=cats.map(c=>`<div class="item-head item"><strong>${esc(c)}</strong><button class="tiny delete" onclick="deleteCategory('${type}','${encodeURIComponent(c)}')">刪除</button></div>`).join('')}
