function deleteCategory(type,enc){const name=decodeURIComponent(enc),used=state.transactions.some(x=>x.type===type&&x.category===name);if(used)return notify('此類別已有記帳紀錄，不能刪除');state.categories[type]=state.categories[type].filter(x=>x!==name);save();renderCategoryManager()}
const MOODS=[['很棒','😄'],['不錯','🙂'],['普通','😐'],['低落','😞'],['很痛苦','😢']],URGES=[['沒有','○'],['輕微','△'],['中等','◐'],['強烈','●'],['復賭','💸']];let selectedMood='普通',selectedUrge='沒有';
